import { ICreditCard } from '@domain/creditCard';
import { DonationSource } from '@domain/donation';
import { formatExpDate } from '@ui/utils/formatExpDate';
import { useTranslation } from 'react-i18next';
import { getPaymentIcon } from '../../utils/getPaymentIcon';
import {
  ACHPaymentIcon,
  ApplePayIcon,
  BitcoinLogoIconSquare,
  CreditCardTypeIcon,
  GooglePayIcon,
  InfoIcon,
  PayPalIcon,
} from '../icons';
import { Label } from '../Label';
import { LastDigits } from '../LastDigits';
import { Meta } from '../Meta';
import { Tooltip, TooltipContent, TooltipTrigger } from '../Tooltip';
import type {
  BankAccountDisplay,
  BasePaymentMethodDisplayProps,
  CreditCardDisplayProps,
  PaymentMethodDisplayProps,
} from './types';

const getCreditCardTypeLabel = (cardType: ICreditCard['cardType'] | undefined) => {
  switch (cardType) {
    case 'american_express':
      return 'American Express';
    case 'master':
      return 'Mastercard';
    default:
      return cardType ? cardType.charAt(0).toUpperCase() + cardType.slice(1) : '';
  }
};

const BankAccountPaymentMethod = ({
  accountType,
  lastDigits,
  showIcon,
  showLastFour,
  showName,
}: PaymentMethodDisplayProps & BankAccountDisplay) => {
  return (
    <div className="flex flex-wrap items-center gap-2">
      {showIcon && <ACHPaymentIcon className="w-[24px]" />}
      {showName && (
        <Label className="capitalize" variant="bold">
          {accountType}
        </Label>
      )}
      {showLastFour && (
        <Meta as="span" className="leading-[1]">
          {!!lastDigits && <LastDigits digits={lastDigits} />}
        </Meta>
      )}
    </div>
  );
};

const DirectCreditCardPaymentMethod = ({
  cardMonth,
  cardType,
  cardYear,
  lastDigits,
  showExpiration = true,
  showIcon = true,
  showLastFour = true,
  showName = true,
  type,
}: CreditCardDisplayProps) => {
  const { t } = useTranslation('finance');
  return (
    <div className="wrap flex items-center justify-between gap-2">
      <div className="relative flex items-center gap-2">
        {showIcon && cardType && <CreditCardTypeIcon className="w-[24px]" type={cardType} />}
        {showName && <Label variant="bold">{getCreditCardTypeLabel(cardType)}</Label>}
        {showIcon && type === 'applepay' && <ApplePayIcon className="w-[24px]" />}
        {showIcon && type === 'google_pay' && <GooglePayIcon className="w-[24px]" />}
        {showLastFour && (
          <Meta as="span" className="leading-[1]">
            {!!lastDigits && <LastDigits digits={lastDigits} />}
          </Meta>
        )}
        {(type === 'applepay' || type === 'google_pay') && (
          <Tooltip>
            <TooltipTrigger>
              <InfoIcon className="w-[13px] text-neutral-500" />
            </TooltipTrigger>
            <TooltipContent>{t('paymentMethod.virtualCardNumberMessage')}</TooltipContent>
          </Tooltip>
        )}
      </div>
      {showExpiration && !!cardMonth && !!cardYear && (
        <Meta>Exp. {formatExpDate(cardMonth, cardYear)}</Meta>
      )}
    </div>
  );
};

type OfflinePaymentMethodProps = BasePaymentMethodDisplayProps & {
  source: DonationSource;
};

export const OfflinePaymentMethod = ({
  showIcon = true,
  showName = true,
  source,
}: OfflinePaymentMethodProps) => {
  const { t } = useTranslation('finance', { keyPrefix: 'common.transactionSource' });
  const Icon = getPaymentIcon({}, source);
  return (
    <div className="wrap items-center gap-2">
      {showIcon && Icon && <Icon className="text-[24px]" />}
      {showName && <Label variant="bold">{t(source)}</Label>}
    </div>
  );
};

export const PaymentMethodDisplay = ({
  showIcon = true,
  showLastFour = true,
  showName = true,
  ...props
}: PaymentMethodDisplayProps) => {
  switch (props?.type) {
    case 'credit_card':
    case 'applepay':
    case 'google_pay':
      return (
        <DirectCreditCardPaymentMethod
          showIcon={showIcon}
          showLastFour={showLastFour}
          showName={showName}
          {...props}
        />
      );
    case 'bank_account':
      return (
        <BankAccountPaymentMethod
          showIcon={showIcon}
          showLastFour={showLastFour}
          showName={showName}
          {...props}
        />
      );
    case 'paypal': {
      const { paypalEmail } = props;
      return (
        <div className="wrap flex items-center">
          <PayPalIcon className="h-[24px] w-[24px]" />

          {paypalEmail && <Meta className="me-0 ms-2 leading-[1]">{paypalEmail}</Meta>}
        </div>
      );
    }
    case 'bitcoin_open_node': {
      const { metadata: charge } = props;
      const { metadata } = charge || {};
      const { email, name } = metadata || {};

      return (
        <div className="wrap items-center p-2">
          {showIcon ? (
            <div className="wrap h-[24px] w-[40px] content-center justify-center overflow-hidden">
              <BitcoinLogoIconSquare className="w-[16px]" />
            </div>
          ) : null}
          {showName && name ? (
            <Label className="capitalize" variant="bold">
              {name}
            </Label>
          ) : null}
          {showName && email ? <Meta className="leading-[1]">{email}</Meta> : null}
        </div>
      );
    }
    default:
      return null;
  }
};

